import { useState, useRef, useEffect, useCallback } from 'react';
import {
  Type, Upload, Shapes, RotateCcw, ShoppingCart, Check,
  Bold, Italic, AlignLeft, AlignCenter, AlignRight,
  Trash2, Copy, MoveUp, MoveDown, ZoomIn, ZoomOut,
  ChevronDown, ChevronRight, Layers, Sparkles,
  RotateCw, FlipHorizontal, Minus, Plus, Palette,
} from 'lucide-react';
import { useCart } from '../context/AppContext';
import { MOCK_PRODUCTS, FIGMA_ASSETS } from '../utils/constants';

const PRODUCTS = [
  { id: 1, name: 'T-Shirt',   price: 10000, sizes: ['XS','S','M','L','XL','XXL'] },
  { id: 2, name: 'Sweat',     price: 15000, sizes: ['S','M','L','XL','XXL'] },
  { id: 3, name: 'Hoodie',    price: 18000, sizes: ['S','M','L','XL','XXL'] },
  { id: 4, name: 'Mug',       price: 8000,  sizes: ['Standard','Grande taille'] },
  { id: 5, name: 'Sneakers',  price: 25000, sizes: ['38','39','40','41','42','43','44','45'] },
  { id: 6, name: 'Casquette', price: 7000,  sizes: ['Unique'] },
];

const PRODUCT_COLORS = [
  { hex: '#FFFFFF', name: 'Blanc' }, { hex: '#1C1C1C', name: 'Noir' },
  { hex: '#1D4ED8', name: 'Bleu' }, { hex: '#DC2626', name: 'Rouge' },
  { hex: '#16A34A', name: 'Vert' }, { hex: '#D97706', name: 'Orange' },
  { hex: '#7C3AED', name: 'Violet' }, { hex: '#DB2777', name: 'Rose' },
  { hex: '#0891B2', name: 'Cyan' }, { hex: '#92400E', name: 'Marron' },
  { hex: '#6B7280', name: 'Gris' }, { hex: '#F9A8D4', name: 'Rose pâle' },
];

const FONTS = [
  { name: 'Poppins', label: 'Poppins' }, { name: 'Impact', label: 'Impact' },
  { name: 'Georgia', label: 'Georgia' }, { name: 'Courier New', label: 'Courier' },
  { name: 'Arial Black', label: 'Arial Black' }, { name: 'Comic Sans MS', label: 'Comic Sans' },
];

const TEXT_COLORS = [
  '#000000','#FFFFFF','#1D4ED8','#DC2626','#16A34A','#D97706',
  '#7C3AED','#DB2777','#0891B2','#F59E0B','#6B7280','#92400E',
];

const SHAPES_LIB = [
  { cat: 'Formes', items: [
    { id: 'rect',     label: 'Rectangle', svg: <rect x="5" y="15" width="90" height="70" rx="4" fill="currentColor"/> },
    { id: 'circle',  label: 'Cercle',    svg: <circle cx="50" cy="50" r="42" fill="currentColor"/> },
    { id: 'triangle',label: 'Triangle',  svg: <polygon points="50,8 92,92 8,92" fill="currentColor"/> },
    { id: 'star5',   label: 'Étoile',    svg: <polygon points="50,5 61,35 95,35 68,57 79,91 50,70 21,91 32,57 5,35 39,35" fill="currentColor"/> },
    { id: 'heart',   label: 'Cœur',      svg: <path d="M50,85 C50,85 10,55 10,30 C10,15 22,5 35,10 C42,13 48,20 50,25 C52,20 58,13 65,10 C78,5 90,15 90,30 C90,55 50,85 50,85Z" fill="currentColor"/> },
    { id: 'diamond', label: 'Diamant',   svg: <polygon points="50,5 95,50 50,95 5,50" fill="currentColor"/> },
    { id: 'arrow',   label: 'Flèche',    svg: <path d="M10,40 L60,40 L60,20 L90,50 L60,80 L60,60 L10,60 Z" fill="currentColor"/> },
    { id: 'hexagon', label: 'Hexagone',  svg: <polygon points="50,5 90,27 90,73 50,95 10,73 10,27" fill="currentColor"/> },
    { id: 'cross',   label: 'Croix',     svg: <path d="M35,5 L65,5 L65,35 L95,35 L95,65 L65,65 L65,95 L35,95 L35,65 L5,65 L5,35 L35,35 Z" fill="currentColor"/> },
    { id: 'ring',    label: 'Anneau',    svg: <><circle cx="50" cy="50" r="42" fill="currentColor"/><circle cx="50" cy="50" r="28" fill="white"/></> },
  ]},
  { cat: 'Streetwear', items: [
    { id: 'lightning', label: 'Éclair',  svg: <polygon points="60,5 30,55 52,55 40,95 70,45 48,45" fill="currentColor"/> },
    { id: 'crown',   label: 'Couronne',  svg: <path d="M10,70 L20,30 L40,55 L50,10 L60,55 L80,30 L90,70 Z" fill="currentColor"/> },
    { id: 'flame',   label: 'Flamme',    svg: <path d="M50,95 C20,95 10,70 25,50 C15,55 12,40 20,30 C25,40 30,38 28,25 C40,35 38,50 45,45 C40,35 48,20 55,10 C55,30 65,35 62,50 C70,40 72,55 65,60 C80,45 78,75 50,95Z" fill="currentColor"/> },
    { id: 'infinity',label: 'Infini',    svg: <path d="M20,50 C20,35 30,25 40,25 C50,25 55,35 60,50 C65,65 70,75 80,75 C90,75 90,65 80,50 C90,50 90,35 80,25 C70,25 65,35 60,50 C55,65 50,75 40,75 C30,75 20,65 20,50Z" fill="none" stroke="currentColor" strokeWidth="8"/> },
    { id: 'wave',    label: 'Vague',     svg: <path d="M5,50 C15,30 25,30 35,50 C45,70 55,70 65,50 C75,30 85,30 95,50" fill="none" stroke="currentColor" strokeWidth="8" strokeLinecap="round"/> },
    { id: 'splash',  label: 'Splash',    svg: <path d="M50,10 C60,5 75,15 80,10 C85,25 95,20 90,35 C100,40 95,55 85,52 C90,65 80,75 70,68 C68,80 55,85 50,75 C45,85 32,80 30,68 C20,75 10,65 15,52 C5,55 0,40 10,35 C5,20 15,25 20,10 C25,15 40,5 50,10Z" fill="currentColor"/> },
    { id: 'bubble',  label: 'Bulle',     svg: <><circle cx="50" cy="45" r="38" fill="currentColor"/><path d="M35,80 L50,95 L60,80Z" fill="currentColor"/></> },
    { id: 'badge',   label: 'Badge',     svg: <polygon points="50,5 61,38 96,38 68,60 79,93 50,72 21,93 32,60 4,38 39,38" fill="currentColor"/> },
    { id: 'drip',    label: 'Drip',      svg: <><rect x="15" y="5" width="70" height="55" rx="6" fill="currentColor"/><path d="M30,55 C30,55 25,75 28,85 C31,90 35,88 35,80 L35,55Z" fill="currentColor"/><path d="M50,55 C50,55 48,80 50,88 C52,93 54,90 54,80 L54,55Z" fill="currentColor"/><path d="M68,55 C68,55 65,70 67,78 C69,83 72,81 72,73 L72,55Z" fill="currentColor"/></> },
    { id: 'eye',     label: 'Oeil',      svg: <><ellipse cx="50" cy="50" rx="42" ry="25" fill="currentColor"/><circle cx="50" cy="50" r="14" fill="white"/><circle cx="50" cy="50" r="8" fill="currentColor" opacity="0.8"/></> },
  ]},
  { cat: 'Stickers', items: [
    { id: 's_fire',  label: '🔥', emoji: '🔥' }, { id: 's_star',  label: '⭐', emoji: '⭐' },
    { id: 's_bolt',  label: '⚡', emoji: '⚡' }, { id: 's_skull', label: '💀', emoji: '💀' },
    { id: 's_crown', label: '👑', emoji: '👑' }, { id: 's_peace', label: '☮️', emoji: '☮️' },
    { id: 's_eye2',  label: '👁️', emoji: '👁️' }, { id: 's_rose',  label: '🌹', emoji: '🌹' },
    { id: 's_yin',   label: '☯️', emoji: '☯️' }, { id: 's_alien', label: '👽', emoji: '👽' },
    { id: 's_gem',   label: '💎', emoji: '💎' }, { id: 's_sword', label: '⚔️', emoji: '⚔️' },
    { id: 's_drgn',  label: '🐉', emoji: '🐉' }, { id: 's_sakura',label: '🌸', emoji: '🌸' },
    { id: 's_wolf',  label: '🐺', emoji: '🐺' }, { id: 's_fist',  label: '✊', emoji: '✊' },
  ]},
];

// Mockups SVG inline
const MockupTShirt = ({ color }) => (
  <svg viewBox="0 0 300 320" style={{ width: '100%', height: '100%' }}>
    <defs>
      <filter id="sh1"><feDropShadow dx="0" dy="8" stdDeviation="10" floodOpacity="0.2"/></filter>
      <linearGradient id="g1" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="white" stopOpacity="0.18"/>
        <stop offset="100%" stopColor="black" stopOpacity="0.08"/>
      </linearGradient>
    </defs>
    <path d="M75,60 L30,85 L50,125 L75,108 L75,280 L225,280 L225,108 L250,125 L270,85 L225,60 L200,40 C190,55 172,65 150,65 C128,65 110,55 100,40 Z" fill={color} filter="url(#sh1)"/>
    <path d="M75,60 L30,85 L50,125 L75,108 L75,280 L225,280 L225,108 L250,125 L270,85 L225,60 L200,40 C190,55 172,65 150,65 C128,65 110,55 100,40 Z" fill="url(#g1)"/>
    <path d="M100,40 C112,58 130,68 150,68 C170,68 188,58 200,40" fill="none" stroke="rgba(0,0,0,0.1)" strokeWidth="2"/>
  </svg>
);

const MockupSweat = ({ color }) => (
  <svg viewBox="0 0 300 320" style={{ width: '100%', height: '100%' }}>
    <defs>
      <filter id="sh2"><feDropShadow dx="0" dy="8" stdDeviation="10" floodOpacity="0.2"/></filter>
      <linearGradient id="g2" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="white" stopOpacity="0.15"/>
        <stop offset="100%" stopColor="black" stopOpacity="0.1"/>
      </linearGradient>
    </defs>
