            </div>

            <div style={card}>
              {sHead('Taille', Type)}
              <div style={{ padding: '10px 12px', display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {selectedProduct.sizes.map(s => (
                  <button key={s} onClick={() => setSelectedSize(s)} style={{ minWidth: 38, padding: '6px 8px', borderRadius: 7, border: `1.5px solid ${selectedSize===s?'#017BFE':'#EBEBEB'}`, background: selectedSize===s?'rgba(1,123,254,0.07)':'white', color: selectedSize===s?'#017BFE':'#555', fontWeight: 700, fontSize: 11, cursor: 'pointer', transition: 'all 0.18s', fontFamily: 'Poppins, sans-serif' }}>{s}</button>
                ))}
              </div>
            </div>
          </>}

          {leftTab === 'outils' && <>
            <div style={{ display: 'flex', gap: 6 }}>
              {[{id:'text',Icon:Type,label:'Texte'},{id:'shape',Icon:Shapes,label:'Éléments'},{id:'image',Icon:Upload,label:'Image'}].map(({id,Icon,label}) => (
                <button key={id} onClick={() => setActiveTool(id)} style={{ flex: 1, padding: '9px 4px', borderRadius: 9, border: `1.5px solid ${activeTool===id?'#017BFE':'#EBEBEB'}`, background: activeTool===id?'#0D0D0D':'white', color: activeTool===id?'white':'#555', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4, fontSize: 11, fontWeight: 700, transition: 'all 0.2s', fontFamily: 'Poppins, sans-serif' }}>
                  <Icon size={15}/>{label}
                </button>
              ))}
            </div>

            {activeTool === 'text' && (
              <div style={card}>
                {sHead('Texte', Type)}
                <div style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10 }}>
                  <textarea value={text} onChange={e => setText(e.target.value)} rows={2} style={{ width: '100%', border: '1.5px solid #EBEBEB', borderRadius: 8, padding: '8px 10px', fontSize: 13, outline: 'none', fontFamily: font, resize: 'none', lineHeight: 1.5 }} />
                  <select value={font} onChange={e => setFont(e.target.value)} style={{ width: '100%', border: '1.5px solid #EBEBEB', borderRadius: 8, padding: '7px 10px', fontSize: 12, outline: 'none', fontFamily: 'Poppins, sans-serif' }}>
                    {FONTS.map(f => <option key={f.name} value={f.name}>{f.label}</option>)}
                  </select>
                  <div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                      <span style={{ fontSize: 11, fontWeight: 700, color: '#555', textTransform: 'uppercase', letterSpacing: '0.04em', fontFamily: 'Poppins, sans-serif' }}>Taille</span>
                      <span style={{ fontSize: 12, fontWeight: 800, color: '#017BFE', fontFamily: 'Poppins, sans-serif' }}>{fontSize}px</span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                      {ib(() => setFontSize(s => Math.max(10, s-2)), Minus, false, 'Réduire')}
                      <input type="range" min={10} max={80} value={fontSize} onChange={e => setFontSize(Number(e.target.value))} style={{ flex: 1, accentColor: '#017BFE' }}/>
                      {ib(() => setFontSize(s => Math.min(80, s+2)), Plus, false, 'Agrandir')}
                    </div>
                  </div>
                  <div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                      <span style={{ fontSize: 11, fontWeight: 700, color: '#555', textTransform: 'uppercase', letterSpacing: '0.04em', fontFamily: 'Poppins, sans-serif' }}>Espacement</span>
                      <span style={{ fontSize: 12, fontWeight: 800, color: '#017BFE', fontFamily: 'Poppins, sans-serif' }}>{letterSpacing}px</span>
                    </div>
                    <input type="range" min={-2} max={20} value={letterSpacing} onChange={e => setLetterSpacing(Number(e.target.value))} style={{ width: '100%', accentColor: '#017BFE' }}/>
                  </div>
                  <div style={{ display: 'flex', gap: 5 }}>
                    {ib(() => setBold(v=>!v),   Bold,        bold,           'Gras')}
                    {ib(() => setItalic(v=>!v), Italic,      italic,         'Italique')}
                    {ib(() => setAlign('left'),  AlignLeft,   align==='left', 'Gauche')}
                    {ib(() => setAlign('center'),AlignCenter, align==='center','Centre')}
                    {ib(() => setAlign('right'), AlignRight,  align==='right','Droite')}
                    {ib(() => setShadow(v=>!v),  Sparkles,    shadow,         'Ombre')}
                  </div>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5 }}>
                    {TEXT_COLORS.map(c => (
                      <button key={c} onClick={() => setTextColor(c)} style={{ width: 24, height: 24, borderRadius: '50%', background: c, padding: 0, border: textColor===c?'2.5px solid #017BFE':'2px solid #EBEBEB', cursor: 'pointer', transform: textColor===c?'scale(1.25)':'scale(1)', transition: 'transform 0.12s', boxShadow: c==='#FFFFFF'?'inset 0 0 0 1px #ccc':'none' }} />
                    ))}
                  </div>
                  <button onClick={addText} style={{ width: '100%', padding: '10px', borderRadius: 9, background: 'linear-gradient(135deg, #017BFE, #00C2FF)', color: 'white', border: 'none', fontWeight: 700, fontSize: 13, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, fontFamily: 'Poppins, sans-serif' }}>
                    <Type size={14}/> Ajouter sur le design
                  </button>
                </div>
              </div>
            )}

            {activeTool === 'shape' && (
              <div style={card}>
                {sHead('Éléments de design', Shapes)}
                <div style={{ padding: 10 }}>
                  <div style={{ display: 'flex', gap: 6, marginBottom: 8, alignItems: 'center' }}>
                    <div style={{ flex: 1 }}>
                      <p style={{ fontSize: 10, fontWeight: 700, color: '#888', marginBottom: 4, textTransform: 'uppercase', fontFamily: 'Poppins, sans-serif' }}>Couleur</p>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                        {TEXT_COLORS.slice(0,8).map(c => (
                          <button key={c} onClick={() => setShapeColor(c)} style={{ width: 22, height: 22, borderRadius: '50%', background: c, padding: 0, border: shapeColor===c?'2.5px solid #017BFE':'2px solid #EBEBEB', cursor: 'pointer', transform: shapeColor===c?'scale(1.2)':'scale(1)', transition: 'transform 0.12s', boxShadow: c==='#FFFFFF'?'inset 0 0 0 1px #ccc':'none' }} />
                        ))}
                      </div>
                    </div>
                    <div>
                      <p style={{ fontSize: 10, fontWeight: 700, color: '#888', marginBottom: 4, textTransform: 'uppercase', fontFamily: 'Poppins, sans-serif' }}>Taille</p>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                        <button onClick={() => setShapeSize(s => Math.max(24, s-10))} style={{ width: 24, height: 24, borderRadius: 5, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Minus size={11}/></button>
                        <span style={{ fontSize: 12, fontWeight: 700, minWidth: 26, textAlign: 'center', color: '#017BFE', fontFamily: 'Poppins, sans-serif' }}>{shapeSize}</span>
                        <button onClick={() => setShapeSize(s => Math.min(160, s+10))} style={{ width: 24, height: 24, borderRadius: 5, border: '1px solid #EBEBEB', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Plus size={11}/></button>
                      </div>
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginBottom: 8 }}>
                    {SHAPES_LIB.map((cat, i) => (
                      <button key={cat.cat} onClick={() => setActiveLib(i)} style={{ padding: '3px 8px', borderRadius: 20, border: 'none', background: activeLib===i?'#0D0D0D':'#F0F0F0', color: activeLib===i?'white':'#555', fontSize: 10, fontWeight: 700, cursor: 'pointer', fontFamily: 'Poppins, sans-serif' }}>{cat.cat}</button>
                    ))}
                  </div>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 5 }}>
                    {SHAPES_LIB[activeLib].items.map((item) => (
                      <button key={item.id} onClick={() => addShape(item)} title={item.label} style={{ width: '100%', aspectRatio: '1', border: '1.5px solid #EBEBEB', borderRadius: 9, background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 0.15s', padding: 5 }}
                        onMouseEnter={e => { e.currentTarget.style.borderColor='#017BFE'; e.currentTarget.style.background='rgba(1,123,254,0.04)'; e.currentTarget.style.transform='scale(1.08)'; }}
                        onMouseLeave={e => { e.currentTarget.style.borderColor='#EBEBEB'; e.currentTarget.style.background='white'; e.currentTarget.style.transform='scale(1)'; }}>
                        {item.emoji ? (
                          <span style={{ fontSize: 24 }}>{item.emoji}</span>
                        ) : (
                          <svg viewBox="0 0 100 100" width={32} height={32} style={{ color: shapeColor, overflow: 'visible' }}>{item.svg}</svg>
                        )}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {activeTool === 'image' && (
              <div style={card}>
                {sHead('Importer une image', Upload)}
                <div style={{ padding: 14 }}>
                  <input ref={fileRef} type="file" accept="image/*" onChange={handleImageUpload} style={{ display: 'none' }} />
                  <button onClick={() => fileRef.current.click()} style={{ width: '100%', border: '2px dashed #017BFE', borderRadius: 10, padding: '24px 16px', background: 'rgba(1,123,254,0.02)', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8, color: '#017BFE' }}>
                    <Upload size={24}/>
                    <span style={{ fontSize: 13, fontWeight: 700, fontFamily: 'Poppins, sans-serif' }}>Cliquer pour importer</span>
                    <span style={{ fontSize: 11, color: '#888', fontFamily: 'Poppins, sans-serif' }}>PNG, JPG, SVG — max 5 MB</span>
                  </button>
                  <div style={{ marginTop: 10, padding: '10px 12px', background: '#F8FBFF', borderRadius: 8, border: '1px solid #E0EDFF' }}>
                    <p style={{ fontSize: 11, color: '#555', lineHeight: 1.7, fontFamily: 'Poppins, sans-serif' }}><strong style={{ color: '#017BFE' }}>Conseil :</strong> PNG avec fond transparent pour un rendu optimal.</p>
                  </div>
                </div>
              </div>
            )}
          </>}
        </div>

        {/* ══ CANVAS ══ */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          {selectedEl && (
            <div style={{ background: 'white', borderRadius: 10, padding: '8px 12px', border: '1px solid #EBEBEB', display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
              <span style={{ fontSize: 11, color: '#888', fontFamily: 'Poppins, sans-serif', marginRight: 2 }}>
                {selectedEl.type==='text'?'Texte':selectedEl.type==='shape'?'Forme':selectedEl.type==='sticker'?'Sticker':'Image'}
              </span>
              <div style={{ width: 1, height: 18, background: '#EBEBEB' }} />
              {ib(() => updateElement(selectedId, { size: Math.max(10,(selectedEl.size||60)-6) }), ZoomOut, false, 'Réduire')}
              <span style={{ fontSize: 12, fontWeight: 700, color: '#017BFE', minWidth: 26, textAlign: 'center', fontFamily: 'Poppins' }}>{Math.round(selectedEl.size||60)}</span>
              {ib(() => updateElement(selectedId, { size: Math.min(200,(selectedEl.size||60)+6) }), ZoomIn, false, 'Agrandir')}
              <div style={{ width: 1, height: 18, background: '#EBEBEB' }} />
              {ib(() => updateElement(selectedId, { rotation: ((selectedEl.rotation||0)+15)%360 }), RotateCw, false, 'Rotation')}
              {ib(() => updateElement(selectedId, { flipX: !selectedEl.flipX }), FlipHorizontal, selectedEl.flipX, 'Miroir')}
              {ib(() => updateElement(selectedId, { zIndex: (selectedEl.zIndex||3)+1 }), MoveUp, false, 'Avancer')}
              {ib(() => updateElement(selectedId, { zIndex: Math.max(1,(selectedEl.zIndex||3)-1) }), MoveDown, false, 'Reculer')}
              <div style={{ width: 1, height: 18, background: '#EBEBEB' }} />
              {ib(() => duplicateElement(selectedId), Copy, false, 'Dupliquer')}
              {ib(() => deleteElement(selectedId), Trash2, false, 'Supprimer', true)}
            </div>
          )}
          <div style={{ flex: 1, borderRadius: 16, overflow: 'hidden', boxShadow: '0 4px 40px rgba(0,0,0,0.12)', background: 'white', minHeight: 560, position: 'relative' }}>
            <DesignCanvas elements={elements} selectedId={selectedId} onSelect={setSelectedId} onUpdate={updateElement} productId={selectedProduct.id} productColor={productColor}/>
            <div style={{ position: 'absolute', bottom: 12, left: '50%', transform: 'translateX(-50%)', background: 'rgba(13,13,13,0.65)', color: 'white', backdropFilter: 'blur(8px)', padding: '5px 14px', borderRadius: 20, fontSize: 11, fontWeight: 600, fontFamily: 'Poppins, sans-serif', pointerEvents: 'none', whiteSpace: 'nowrap' }}>
              Glissez pour déplacer · Poignée bleue pour redimensionner
            </div>
          </div>
        </div>

        {/* ══ DROITE ══ */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          <div style={card}>
            {sHead(`Calques (${elements.length})`, Layers)}
            <div style={{ padding: '6px 10px', maxHeight: 220, overflowY: 'auto' }}>
              {elements.length === 0 ? (
                <p style={{ fontSize: 12, color: '#bbb', textAlign: 'center', padding: '16px 0', fontFamily: 'Poppins, sans-serif' }}>Aucun élément</p>
              ) : (
                [...elements].reverse().map(el => (
                  <div key={el.id} onClick={() => setSelectedId(el.id)} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '7px 8px', borderRadius: 8, cursor: 'pointer', background: selectedId===el.id?'rgba(1,123,254,0.06)':'transparent', border: `1px solid ${selectedId===el.id?'rgba(1,123,254,0.18)':'transparent'}`, marginBottom: 3, transition: 'all 0.12s' }}>
                    <span style={{ fontSize: 16, flexShrink: 0 }}>{el.type==='text'?'𝗧':el.type==='sticker'?el.emoji:el.type==='image'?'🖼':'◆'}</span>
                    <span style={{ fontSize: 12, flex: 1, color: '#444', fontFamily: 'Poppins, sans-serif', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{el.type==='text'?`"${el.text}"`:el.type==='sticker'?'Sticker':el.type==='shape'?'Forme':'Image'}</span>
                    <button onClick={e => { e.stopPropagation(); deleteElement(el.id); }} style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 2, display: 'flex', opacity: 0.4 }}><Trash2 size={12} color="#666"/></button>
                  </div>
                ))
              )}
            </div>
          </div>

          {selectedEl && (
            <div style={card}>
              {sHead('Apparence', Palette)}
              <div style={{ padding: 12 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 5 }}>
                  <span style={{ fontSize: 11, fontWeight: 700, color: '#555', textTransform: 'uppercase', letterSpacing: '0.04em', fontFamily: 'Poppins, sans-serif' }}>Opacité</span>
                  <span style={{ fontSize: 12, fontWeight: 800, color: '#017BFE', fontFamily: 'Poppins, sans-serif' }}>{Math.round((selectedEl.opacity??1)*100)}%</span>
                </div>
                <input type="range" min={0.1} max={1} step={0.05} value={selectedEl.opacity??1} onChange={e => updateElement(selectedId, { opacity: parseFloat(e.target.value) })} style={{ width: '100%', accentColor: '#017BFE' }}/>
                {selectedEl.type === 'shape' && (
                  <div style={{ marginTop: 12 }}>
                    <p style={{ fontSize: 11, fontWeight: 700, color: '#555', textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: 6, fontFamily: 'Poppins, sans-serif' }}>Couleur</p>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5 }}>
                      {TEXT_COLORS.map(c => (
                        <button key={c} onClick={() => updateElement(selectedId, { color: c })} style={{ width: 22, height: 22, borderRadius: '50%', background: c, padding: 0, border: selectedEl.color===c?'2.5px solid #017BFE':'2px solid #EBEBEB', cursor: 'pointer', transform: selectedEl.color===c?'scale(1.25)':'scale(1)', transition: 'transform 0.12s', boxShadow: c==='#FFFFFF'?'inset 0 0 0 1px #ccc':'none' }} />
                      ))}
                    </div>
                  </div>
                )}
                <div style={{ marginTop: 12 }}>
                  <p style={{ fontSize: 11, fontWeight: 700, color: '#555', textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: 6, fontFamily: 'Poppins, sans-serif' }}>Rotation</p>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                    {ib(() => updateElement(selectedId, { rotation: ((selectedEl.rotation||0)-5+360)%360 }), RotateCcw, false, '-5°')}
                    <span style={{ flex: 1, textAlign: 'center', fontSize: 12, fontWeight: 700, color: '#017BFE', fontFamily: 'Poppins' }}>{selectedEl.rotation||0}°</span>
                    {ib(() => updateElement(selectedId, { rotation: ((selectedEl.rotation||0)+5)%360 }), RotateCw, false, '+5°')}
                  </div>
                </div>
              </div>
            </div>
          )}

          <div style={{ background: 'linear-gradient(135deg, #017BFE 0%, #00C2FF 100%)', borderRadius: 14, overflow: 'hidden' }}>
            <div style={{ padding: 20, color: 'white', textAlign: 'center' }}>
              <p style={{ fontSize: 11, opacity: 0.8, marginBottom: 3, fontFamily: 'Poppins, sans-serif', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Prix estimé</p>
              <p style={{ fontSize: 32, fontWeight: 900, marginBottom: 2, fontFamily: 'Poppins, sans-serif' }}>{selectedProduct.price.toLocaleString('fr-FR')}</p>
              <p style={{ fontSize: 12, opacity: 0.75, marginBottom: 18, fontFamily: 'Poppins, sans-serif' }}>FCFA · Taille {selectedSize}</p>
              <button onClick={handleAddToCart} style={{ width: '100%', padding: '12px', background: 'white', color: '#017BFE', border: 'none', borderRadius: 10, fontWeight: 800, fontSize: 14, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, fontFamily: 'Poppins, sans-serif', transition: 'opacity 0.2s' }} onMouseEnter={e => e.currentTarget.style.opacity='0.88'} onMouseLeave={e => e.currentTarget.style.opacity='1'}>
                {added ? <><Check size={15}/> Ajouté !</> : <><ShoppingCart size={15}/> Commander</>}
              </button>
            </div>
          </div>

          <div style={{ ...card, background: '#F8FBFF' }}>
            {sHead('Conseils', Sparkles)}
            <ul style={{ padding: '8px 14px 12px', listStyle: 'none', display: 'flex', flexDirection: 'column', gap: 7 }}>
              {['PNG fond transparent = meilleur rendu','Zone pointillée = zone d\'impression','Cliquez un élément pour le sélectionner','Poignée bleue pour redimensionner'].map((tip, i) => (
                <li key={i} style={{ display: 'flex', gap: 7, fontSize: 11, color: '#555', lineHeight: 1.6, fontFamily: 'Poppins, sans-serif' }}>
                  <span style={{ color: '#017BFE', fontWeight: 800, flexShrink: 0 }}>·</span>{tip}
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}
